✨ 一级标题示例这里是段落示例。
二级标题示例三级标题示例
💻 代码高亮示例下面是 C 语言代码块展示效果：
#include &lt;stdio.h&gt;int main() &#123;    printf(&quot;Hello Hexo + Fluid!\n&quot;);    return 0;&#125;

libnetfilter_queue介绍在 Linux 防火墙中，iptables 本身并不处理数据包，它只是一个“规则描述工具”。真正的数据包裁决发生在内核 Netfilter 框架中。当我们通过iptables使用 -j NFQUEUE 参数下发规则时，本质上是告诉内核：匹配到该规则的 skb 不要立刻放行或拦截，而是进入NFQUEUE子系统，送往用户态程序，等待用户态来决定如何处理这个数据包。而libnetfilter_queue 就是 Linux 下 Netfilter 子系统提供的一个用户态开发库，专门用于用户态接收、分析、修改、处理，再决定是否放行&#x2F;拦截网络数据包，它是实现 NFQUEUE 功能的核心组件。
iptables 下发规则iptables规则下发到nfqueue，一般使用方法为：
iptables -I INPUT -j NFQUEUE --queue-num 0 

简而言之：就是下发了一条规则，向内核 filter表(默认)，注册到了INPUT链，当有数据包到INPUT链，转交给NFQUEUE子系统进行处理，并且入0号队列
iptables用户态调用流程iptables() └── do_command()      └── do_command4()           └── iptc_commit()                └── setsockopt(fd, SOL_IP, IPT_SO_SET_REPLACE, ...)

用户态主要做的就是： 

构造整张规则表的数据iptables 在用户态内部并不是“只构造一条规则”，而是会：解析当前系统中 已有的全部规则，然后将新规则插入到对应链（这里是 INPUT），再重新生成一整张完整的规则表数据结构，也就是说：iptables 在用户态做的是“整表重建”，不是“单条规则增量修改”。

通过 setsockopt 下发整张规则表给内核把包含所有链（INPUT、OUTPUT、FORWARD）所有规则、所有 match、所有 target（包括 NFQUEUE）的一整块内存，一次性发送给内核。然后iptables使命就结束了，后续的所有规则匹配与数据包处理，全部发生在内核中，iptables进程是不会参与任何一个数据包的处理的。


iptables内核态调用流程__x64_sys_setsockopt() └── do_sys_setsockopt()      └── __sys_setsockopt()          └── raw_setsockopt()               └── ip_setsockopt()                    └── nf_setsockopt()                        └── do_ipt_set_ctl()                             └── do_replace()                                  └── __do_replace()

内核态主要做的就是：

为整张规则表分配内核内存

newinfo = xt_alloc_table_info(tmp.size);if (!newinfo)	return -ENOMEM;

再将所有规则内容完整拷贝进内核

/* 从用户态拷贝 规则表头 */if (copy_from_sockptr(&amp;tmp, arg, sizeof(tmp)) != 0)	return -EFAULT; /* 从用户态拷贝 真正的规则内容 进内核 */if (copy_from_sockptr_offset(loc_cpu_entry, arg, sizeof(tmp),		tmp.size) != 0) &#123;	ret = -EFAULT;	goto free_newinfo;&#125;

解析并绑定目标（NFQUEUE 关键点）

 /* 规则 翻译 和 校验 */ret = translate_table(net, newinfo, loc_cpu_entry, &amp;tmp);if (ret != 0)	goto free_newinfo; /* 绑定target */t = ipt_get_target(e);target = xt_request_find_target(NFPROTO_IPV4, t-&gt;u.user.name,				t-&gt;u.user.revision);if (IS_ERR(target)) &#123;	ret = PTR_ERR(target);	goto cleanup_matches;&#125;t-&gt;u.kernel.target = target;

替换旧规则表

/* * Ensure contents of newinfo are visible before assigning to * private. */smp_wmb();table-&gt;private = newinfo;/* make sure all cpus see new -&gt;private value */smp_mb();

疑问点
为什么“哪怕只加一条规则”，也必须整体替换？iptables 的规则表不是链表，而是“连续内存 + 偏移跳转”的结构。

为什么会整体替换呢？因为Netfilter 规则是在“数据包热路径”上被每秒几十万次并发读取的，规则表是“每个包都要读的共享结构”只能“无锁读取 + 整体原子切换”，不能“在线修改细节”，这样能最大程度提高性能。


skb 如何在 INPUT 链命中 NFQUEUE一个数据包从网卡进入 Linux 内核后，首先进入的是软中断收包流程：
网卡中断 └── napi_poll()     └── 驱动收包          └── __netif_receive_skb_core()              └── ip_rcv()                   └── dst_input()                       └── ip_local_deliver()                            └── LOCAL_IN NF_HOOK()                                └── nf_hook()                                     └── nf_hook_slow()                                          └── nf_hook_entry_hookfn()                                              └── ipt_do_table()                                                  └── nfqueue_tg()                 

nfqueue_tg实现如下，其实就是置NF_QUEUE，并且把queuenum也返出去
#define NF_QUEUE_NR(x) ((((x) &lt;&lt; 16) &amp; NF_VERDICT_QMASK) | NF_QUEUE)// Expands to((((tinfo-&gt;queuenum) &lt;&lt; 16) &amp; 0xffff0000) | 3)static unsigned intnfqueue_tg(struct sk_buff *skb, const struct xt_action_param *par)&#123;	const struct xt_NFQ_info *tinfo = par-&gt;targinfo;	return NF_QUEUE_NR(tinfo-&gt;queuenum);&#125;


如果命中了NFQUEUE的规则，那返回的verdict，前两字节是命中规则的queuenum号，后两字节是标识NF_QUEUE标志，标识该数据包要送往NFQUEUE等待裁决，而非在这里直接放行或拦截
int nf_hook_slow(struct sk_buff *skb, struct nf_hook_state *state,		 const struct nf_hook_entries *e, unsigned int s)&#123;	unsigned int verdict;	int ret;	for (; s &lt; e-&gt;num_hook_entries; s++) &#123;		verdict = nf_hook_entry_hookfn(&amp;e-&gt;hooks[s], skb, state);		switch (verdict &amp; NF_VERDICT_MASK) &#123;		/* 直接放行 */		case NF_ACCEPT:			break;		/* 直接丢弃 */		case NF_DROP:			kfree_skb_reason(skb,					 SKB_DROP_REASON_NETFILTER_DROP);			ret = NF_DROP_GETERR(verdict);			if (ret == 0)				ret = -EPERM;			return ret;		/* 进入nfqueue，由用户态程序决定是否放行 */		case NF_QUEUE:			ret = nf_queue(skb, state, s, verdict);			if (ret == 1)				continue;			return ret;		default:			/* Implicit handling for NF_STOLEN, as well as any other			 * non conventional verdicts.			 */			return 0;		&#125;	&#125;	return 1;&#125;

再看nf_queue的调用逻辑：
nf_queue()└── __nf_queue()    └── nfqnl_enqueue_packet()

入队其实就是根据传入的queuenum号，先找到对应的实例instance
/* rcu_read_lock()ed by nf_hook_thresh */queue = instance_lookup(q, queuenum);if (!queue)	return -ESRCH;

然后将包信息通过netlink发送给用户态进程，发送失败，直接返回；发送成功，则将这个entry加入到队列实例链表上，等待用户态裁决
/* nfnetlink_unicast will either free the nskb or add it to a socket  * netlink 把信息发往用户态 */err = nfnetlink_unicast(nskb, net, queue-&gt;peer_portid);if (err &lt; 0) &#123;	if (queue-&gt;flags &amp; NFQA_CFG_F_FAIL_OPEN) &#123;		failopen = 1;		err = 0;	&#125; else &#123;		queue-&gt;queue_user_dropped++;	&#125;	goto err_out_unlock;&#125;/* 发往用户态成功了，将这个entry暂存到链表里去，到时候好找 */__enqueue_entry(queue, entry);


用户态程序是如何裁决数据包的基本流程：
nfq_open() └── nfq_bind_pf(AF_INET)     └── nfq_create_queue(queue_num, callback)         └── nfq_set_mode(NFQNL_COPY_PACKET)             └── recv(fd)                 └── nfq_handle_packet()                     └── 回调函数 callback()                          └── nfq_set_verdict()

代码实现：
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;errno.h&gt;#include &lt;string.h&gt;#include &lt;limits.h&gt;#include &lt;sys/socket.h&gt;#include &lt;arpa/inet.h&gt;/* 注意下这个头文件需要在arpa/inet.h之后包含，否则会报in_addr重定义 */#include &lt;linux/netfilter.h&gt;#include &lt;libnetfilter_queue/libnetfilter_queue.h&gt;/* 队列序号 */#define QUEUE_NUM   1/* 注意我们是hook input链，针对udp大包，需要 USHRT_MAX 才能完全存储 */#define MAX_BUF     USHRT_MAX#define QUEUE_MAXLEN 4096static int cb(struct nfq_q_handle *qh, struct nfgenmsg *nfmsg,              struct nfq_data *nfa, void *data)&#123;    unsigned char *payload = NULL;    int len = nfq_get_payload(nfa, &amp;payload);    printf(&quot;got packet, size = %d\n&quot;, len);    struct nfqnl_msg_packet_hdr *ph = nfq_get_msg_packet_hdr(nfa);    if (!ph) &#123;        printf(&quot;nfq_get_msg_packet_hdr failed\n&quot;);        return -1;    &#125;    /* 这里要注意，需要转成主机序 */    uint32_t id = ntohl(ph-&gt;packet_id);    return nfq_set_verdict(qh, id, NF_ACCEPT, 0, NULL);&#125;int main()&#123;    struct nfq_handle *h = NULL;    struct nfq_q_handle *qh = NULL;    int fd = -1;    int ret;    char buf[MAX_BUF] __attribute__ ((aligned));    h = nfq_open();    if (!h) &#123;        printf(&quot;nfq_open failed\n&quot;);        goto out;    &#125;    if (nfq_unbind_pf(h, AF_INET) &lt; 0) &#123;        printf(&quot;nfq_unbind_pf failed\n&quot;);        goto out;    &#125;    if (nfq_bind_pf(h, AF_INET) &lt; 0) &#123;        printf(&quot;nfq_bind_pf failed\n&quot;);        goto out;    &#125;    qh = nfq_create_queue(h, QUEUE_NUM, &amp;cb, NULL);    if (!qh) &#123;        printf(&quot;nfq_create_queue failed\n&quot;);        goto out;    &#125;    /* 拷贝整个数据包 */    ret = nfq_set_mode(qh, NFQNL_COPY_PACKET, 0xffff);    if (ret &lt; 0) &#123;        printf(&quot;nfq_set_mode failed\n&quot;);        goto out;    &#125;    /* 调大内核 nfqueue 环形队列长度，     * 这表示内核最大能缓存多少个尚未被用户态处理的包 */    ret = nfq_set_queue_maxlen(qh, QUEUE_MAXLEN);    if (ret &lt; 0) &#123;        printf(&quot;nfq_set_queue_maxlen failed\n&quot;);    &#125;    fd = nfq_fd(h);    if (fd &lt; 0) &#123;        printf(&quot;nfq_fd failed\n&quot;);        goto out;    &#125;    printf(&quot;nfqueue started, queue=%d\n&quot;, QUEUE_NUM);    while (1) &#123;        int n = recv(fd, buf, sizeof(buf), 0);        if (n &lt; 0) &#123;            if (errno == EINTR)                continue;            perror(&quot;recv&quot;);            break;        &#125;        if (n == 0) &#123;            printf(&quot;recv returned 0\n&quot;);            break;        &#125;        ret = nfq_handle_packet(h, buf, n);        if (ret &lt; 0) &#123;            printf(&quot;nfq_handle_packet error: %d\n&quot;, ret);        &#125;    &#125;out:    if (qh)        nfq_destroy_queue(qh);    if (h)        nfq_close(h);    return 0;&#125;

裁决下发的函数：
int nfq_set_verdict(struct nfq_q_handle *qh, uint32_t id,		    uint32_t verdict, uint32_t data_len,		    const unsigned char *buf)&#123;	return __set_verdict(qh, id, verdict, 0, 0, data_len, buf,						NFQNL_MSG_VERDICT);&#125;

对应内核处理函数：
nfqnl_recv_verdict() └── nfqnl_reinject()      └── nf_reinject()

这里将决定数据包最终的命运：放行 or 拦截 or 再次入队
void nf_reinject(struct nf_queue_entry *entry, unsigned int verdict)&#123;  ......	switch (verdict &amp; NF_VERDICT_MASK) &#123;	case NF_ACCEPT:	case NF_STOP:		/* 放行啦，继续执行其后续流程，送往协议栈上层处理函数，ip_local_deliver_finish */		local_bh_disable();		entry-&gt;state.okfn(entry-&gt;state.net, entry-&gt;state.sk, skb);		local_bh_enable();		break;	case NF_QUEUE:		/* 太扯了，又让我再次入队 */		err = nf_queue(skb, &amp;entry-&gt;state, i, verdict);		if (err == 1)			goto next_hook;		break;	case NF_STOLEN:		break;	default:		/* 其它，比如 drop，那就直接释放数据包即可 */		kfree_skb(skb);	&#125;   ......&#125;

基本处理流程大体如上。
